/* CÓDIGO UPDATE: Generador de Cupón Único */
const items = $input.all();
const item = items[0].json;

// IMPORTANTE: Extraemos los datos del BODY
const userData = item.body || item; 

const couponPrefix = 'DEV-';
const timePart = Date.now().toString(36).slice(-4).toUpperCase();
const rawName = userData.nombre ? String(userData.nombre).trim() : '';
const cleanName = rawName.normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-zA-Z0-9]/g, '');
const nameSuffix = cleanName.length >= 2 ? cleanName.slice(-2).toUpperCase() : 'XX';

const fullCoupon = couponPrefix + timePart + nameSuffix;

return [{
  json: {
    name: userData.nombre,       
    email: userData.email,     
    whatsapp: userData.telefono,
    birthday: userData.cumpleaños, 
    coupon_code: fullCoupon
  }
}];
